// Ստեղծում ենք տարիքի փոփոխականը
let age = 20;

// Ստուգում ենք պայմանը
if (age >= 18) {
  // Եթե պայմանը ճիշտ է (true)
  console.log("Դուք չափահաս եք:");
} else {
  // Եթե պայմանը սխալ է (false)
  console.log("Դուք դեռ փոքր եք:");
}

// Լրացուցիչ փորձ. կարող ես փոխել age-ի արժեքը 15-ի և տեսնել, թե ինչպես կփոխվի պատասխանը
